def main():
    output_dir = os.path.join(os.path.dirname(__file__), 'questions')
    os.makedirs(output_dir, exist_ok=True)
    output_path = os.path.join(output_dir, 'theology.json')

    all_questions = []
    seen = set()

    for tier, qs in QUESTIONS.items():
        for q in qs:
            key = (q['question'].strip().lower(), q['answer'].strip().lower())
            if key in seen:
                continue
            seen.add(key)
            entry = {
                'tier': tier,
                'question': q['question'],
                'answer': q['answer'],
                'choices': q['choices'],
            }
            all_questions.append(entry)

    # Sort by tier then shuffle within each tier for variety
    by_tier = {}
    for q in all_questions:
        by_tier.setdefault(q['tier'], []).append(q)
    for tier_qs in by_tier.values():
        random.shuffle(tier_qs)

    final = []
    for tier in sorted(by_tier):
        final.extend(by_tier[tier])

    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(final, f, indent=2, ensure_ascii=False)

    counts = Counter(q['tier'] for q in final)
    print('Theology tiers:', dict(sorted(counts.items())), 'total:', len(final))
    print(f'Written to: {output_path}')


if __name__ == '__main__':
    main()
